-- =============================================================================
-- VERIFICACIÓN
-- =============================================================================
select 'RESUMEN DE DATOS CARGADOS:' as mensaje;
select 'businesses', count(*) from public.businesses
union all select 'profiles', count(*) from public.profiles
union all select 'employee_schedules', count(*) from public.employee_schedules
union all select 'service_categories', count(*) from public.service_categories
union all select 'services', count(*) from public.services
union all select 'service_variants', count(*) from public.service_variants
union all select 'employee_services', count(*) from public.employee_services
union all select 'clients', count(*) from public.clients
union all select 'client_preferred_services', count(*) from public.client_preferred_services
union all select 'appointments', count(*) from public.appointments
union all select 'transactions', count(*) from public.transactions
union all select 'expenses', count(*) from public.expenses
union all select 'employee_absences', count(*) from public.employee_absences
union all select 'product_categories', count(*) from public.product_categories
union all select 'products', count(*) from public.products
union all select 'product_variants', count(*) from public.product_variants
union all select 'inventory_locations', count(*) from public.inventory_locations
union all select 'inventory_stock', count(*) from public.inventory_stock
union all select 'inventory_movements', count(*) from public.inventory_movements
order by 1;
